import jsPDF from 'jspdf'
import 'jspdf-autotable'

const LOGO_B64 = 'data:image/png;base64,'

function fmt(n) {
  return Math.round(n || 0).toLocaleString('id-ID')
}

function fmtDate(d) {
  if (!d) return '-'
  return new Date(d).toLocaleDateString('id-ID', { day: '2-digit', month: '2-digit', year: 'numeric' })
}

function calcItem(item) {
  return item.qty * (item.price || 0) * (1 - (item.disc || 0) / 100)
}

export function generatePDF(quotation) {
  const doc = new jsPDF({ unit: 'mm', format: 'a4' })
  const pw = doc.internal.pageSize.getWidth()
  const { info, items, customer } = quotation

  const tot = items.filter(r => r.t === 'i').reduce((s, r) => s + calcItem(r), 0)
  const dp = info.discount_pct || 0
  const vp = info.vat_pct || 12
  const da = tot * dp / 100
  const sub = tot - da
  const vat = sub * vp / 100
  const grand = sub + vat

  const ML = 14, MR = 14
  const CW = pw - ML - MR

  // ===== HEADER: Logo (left) + Company name & address (right) =====
  let y = 12
  try {
    // Logo aspect ratio from source: 600x229 -> keep proportion, width 58mm
    const logoW = 58
    const logoH = logoW * (229 / 600)
    doc.addImage(LOGO_B64, 'PNG', ML, y - 4, logoW, logoH)
  } catch (e) { /* logo failed, continue without it */ }

  doc.setTextColor(0)
  doc.setFont(undefined, 'bold')
  doc.setFontSize(13)
  doc.text('PT. GLOBAL SAHABAT OTOMASI', pw - MR, y, { align: 'right' })
  doc.setFont(undefined, 'normal')
  doc.setFontSize(7.5)
  doc.setTextColor(60, 60, 60)
  doc.text('Jl. Industri Sel. IV Blok GG.5.O Kawasan Industri Jababeka', pw - MR, y + 5, { align: 'right' })
  doc.text('Pasirsari, Cikarang Selatan, Bekasi Regency 17550', pw - MR, y + 9, { align: 'right' })
  doc.text('www.gso.co.id', pw - MR, y + 13, { align: 'right' })

  y = 32

  // ===== QUOTATION TITLE =====
  doc.setTextColor(0)
  doc.setFont(undefined, 'bold')
  doc.setFontSize(15)
  doc.text('QUOTATION', pw / 2, y, { align: 'center' })
  y += 6

  // ===== TO / INFO BOX (independent heights, two columns) =====
  const boxTop = y
  const leftW = CW * 0.58
  const rightW = CW * 0.42
  const rightX = ML + leftW

  doc.setDrawColor(0, 32, 96)
  doc.setLineWidth(0.3)
  doc.setFontSize(8)

  // ---- Compute LEFT box height ----
  const addrLines = customer.address ? doc.splitTextToSize(customer.address, leftW - 6) : []
  const toSectionH = 5 + 5 + (addrLines.length ? addrLines.length * 3.8 + 1 : 2)
  const subRowH = 5
  const leftBoxH = toSectionH + subRowH * 3

  // ---- Compute RIGHT box height (7 rows now incl. Create by) ----
  const infoRows = [
    ['Quotation No.', info.qo_number || ''],
    ['Date', fmtDate(info.date)],
    ['Sales Name', info.sales_name || ''],
    ['Mobile', info.sales_mobile || ''],
    ['Payment', info.payment_terms || ''],
    ['Create by', info.sales_name || '-'],
    ['Engineer', info.engineer || '-'],
  ]
  const rightRowH = 5
  const mobileExtraGap = 4
  const rightBoxH = infoRows.length * rightRowH + mobileExtraGap

  const leftFinalH = leftBoxH
  const rightFinalH = rightBoxH

  // ---- Draw LEFT box ----
  doc.rect(ML, boxTop, leftW, leftFinalH)
  let leftY = boxTop + 4
  doc.setFont(undefined, 'normal')
  doc.setFontSize(7.5)
  doc.setTextColor(30, 41, 59)
  doc.text('To :', ML + 2, leftY)
  doc.line(ML + 2, leftY + 0.6, ML + 8, leftY + 0.6) // underline "To :"
  leftY += 4.5
  doc.setFont(undefined, 'bold')
  doc.setFontSize(8.5)
  doc.setTextColor(0)
  doc.text(customer.company || '-', ML + 2, leftY)
  leftY += 4
  if (addrLines.length) {
    doc.setFont(undefined, 'normal')
    doc.setFontSize(7.5)
    doc.setTextColor(50, 50, 50)
    doc.text(addrLines, ML + 2, leftY)
    leftY += addrLines.length * 3.8
  }

  leftY = boxTop + toSectionH
  doc.line(ML, leftY, ML + leftW, leftY)
  leftY += 4
  doc.setFont(undefined, 'normal')
  doc.setFontSize(7.5)
  doc.setTextColor(30, 41, 59)
  doc.text('Up :', ML + 2, leftY)
  doc.line(ML + 2, leftY + 0.6, ML + 8, leftY + 0.6)
  doc.setTextColor(0)
  doc.text(customer.contact || '-', ML + 14, leftY)

  leftY = boxTop + toSectionH + subRowH
  doc.line(ML, leftY, ML + leftW, leftY)
  leftY += 4
  doc.setTextColor(30, 41, 59)
  doc.text('Telp / Mobile:', ML + 2, leftY)
  doc.line(ML + 2, leftY + 0.6, ML + 22, leftY + 0.6)
  doc.setTextColor(0)
  doc.text(customer.tel || '-', ML + 30, leftY)

  leftY = boxTop + toSectionH + subRowH * 2
  doc.line(ML, leftY, ML + leftW, leftY)
  leftY += 4
  doc.setTextColor(30, 41, 59)
  doc.text('Fax / Email :', ML + 2, leftY)
  doc.line(ML + 2, leftY + 0.6, ML + 20, leftY + 0.6)
  doc.setTextColor(0)
  doc.text(customer.email || '-', ML + 30, leftY)

  // ---- Draw RIGHT box ----
  doc.rect(rightX, boxTop, rightW, rightFinalH)
  doc.setFontSize(7.5)
  infoRows.forEach((row, i) => {
    const gapOffset = i >= 4 ? mobileExtraGap : 0
    const ry = boxTop + rightRowH * i + gapOffset
    if (i > 0) doc.line(rightX, ry, rightX + rightW, ry)
    doc.setFont(undefined, 'normal')
    doc.setTextColor(30, 41, 59)
    doc.text(row[0], rightX + 2, ry + rightRowH / 2 + 1.2)
    doc.setFont(undefined, 'bold')
    doc.setTextColor(0)
    const valX = rightX + rightW * 0.42
    const valLines = doc.splitTextToSize(String(row[1] || '-'), rightW * 0.55)
    doc.text(valLines, valX, ry + rightRowH / 2 + 1.2)
  })
  // vertical divider in right box
  doc.line(rightX + rightW * 0.40, boxTop, rightX + rightW * 0.40, boxTop + rightFinalH)

  y = boxTop + Math.max(leftFinalH, rightFinalH) + 5

  // ===== ITEMS TABLE =====
  let nc = 0
  const body = []
  items.forEach(r => {
    if (r.t === 'g') {
      body.push([{ content: r.label || '', colSpan: 7, styles: { fontStyle: 'bold', fillColor: [235, 238, 245], halign: 'center' } }])
    } else if (r.t === 'n') {
      body.push([{ content: r.text || '', colSpan: 7, styles: { textColor: [120, 120, 120], fontSize: 7.5 } }])
    } else if (r.t === 'i') {
      nc++
      body.push([
        nc, r.part || '',
        { content: r.name || '', styles: { fontStyle: 'normal' } },
        '' + r.qty,
        fmt(r.price || 0),
        r.disc ? r.disc + '%' : '-',
        fmt(calcItem(r))
      ])
      ;(r.subs || []).forEach((s, si) => {
        body.push([
          { content: `${nc}.${si + 1}`, styles: { textColor: [120, 120, 120] } },
          '', s.text || '', '', '', '', ''
        ])
      })
    }
  })

  doc.autoTable({
    startY: y,
    head: [['No.', 'Part Number', 'Description', 'Qty', 'Unit Price', 'Disc', 'Price']],
    body,
    headStyles: { fillColor: [0, 32, 96], textColor: 255, fontSize: 8, halign: 'center', lineWidth: 0.2, lineColor: [0, 32, 96] },
    bodyStyles: { fontSize: 8, lineWidth: 0.2, lineColor: [180, 180, 180] },
    columnStyles: {
      0: { cellWidth: 9, halign: 'center' },
      1: { cellWidth: 24 },
      3: { cellWidth: 12, halign: 'center' },
      4: { cellWidth: 26, halign: 'right' },
      5: { cellWidth: 14, halign: 'center' },
      6: { cellWidth: 26, halign: 'right' }
    },
    theme: 'grid',
    margin: { left: ML, right: MR }
  })

  // ===== NOTES (left) + TOTALS (right) =====
  const afterTableY = doc.lastAutoTable.finalY + 3
  const notesW = CW * 0.6
  const totalsW = CW * 0.38
  const totalsX = ML + CW - totalsW

  // Notes box left
  let ny = afterTableY
  if (info.notes) {
    doc.setDrawColor(180, 180, 180)
    doc.setFontSize(7)
    doc.setFont(undefined, 'bold')
    doc.setTextColor(0)
    doc.text('Notes:', ML, afterTableY + 3)
    doc.setFont(undefined, 'normal')
    const noteLines = info.notes.split('\n').filter(Boolean)
    ny = afterTableY + 7
    noteLines.forEach(line => {
      doc.text(line, ML, ny, { maxWidth: notesW })
      ny += 3.6
    })
  }

  // Totals box right
  const totalRows = [
    ['TOTAL', fmt(tot)],
    ['DISKON', dp > 0 ? `(${dp}%) - ${fmt(da)}` : '-'],
    ['SUB TOTAL', fmt(sub)],
    [`VAT ${vp}%`, fmt(vat)],
  ]
  let ty = afterTableY
  doc.setDrawColor(0, 32, 96)
  doc.setFontSize(8)
  totalRows.forEach(([label, val]) => {
    doc.setFont(undefined, 'normal')
    doc.text(label, totalsX + 2, ty + 4)
    doc.setFont(undefined, 'normal')
    doc.text(val, totalsX + totalsW - 2, ty + 4, { align: 'right' })
    doc.line(totalsX, ty + 6, totalsX + totalsW, ty + 6)
    ty += 6
  })
  // Grand total highlighted
  doc.setFillColor(240, 240, 245)
  doc.rect(totalsX, ty, totalsW, 8, 'F')
  doc.setFont(undefined, 'bold')
  doc.setFontSize(9)
  doc.text('GRAND TOTAL', totalsX + 2, ty + 5.5)
  doc.text(fmt(grand), totalsX + totalsW - 2, ty + 5.5, { align: 'right' })
  doc.rect(totalsX, afterTableY, totalsW, (ty - afterTableY) + 8)

  // ===== FOOTER tagline =====
  const footerY = Math.max(ny || afterTableY + 20, ty + 18)
  doc.setFont(undefined, 'bolditalic')
  doc.setFontSize(9)
  doc.setTextColor(0, 32, 96)
  doc.text('PT Global Sahabat Otomasi', pw / 2, footerY, { align: 'center' })
  doc.setTextColor(220, 38, 38)
  doc.text('"Your Automation Partner"', pw / 2, footerY + 5, { align: 'center' })

  const filename = (info.qo_number || 'quotation').replace(/[/\\]/g, '-') + '.pdf'
  doc.save(filename)
}
